import React, { useState, useEffect } from 'react';
import {
  Box,
  Typography,
  Paper,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Divider,
  Button,
  TextField,
  CircularProgress,
  Alert
} from '@mui/material';
import DescriptionIcon from '@mui/icons-material/Description';
import UploadFileIcon from '@mui/icons-material/UploadFile';
import AttachmentIcon from '@mui/icons-material/Attachment';
import { styled } from '@mui/material/styles';

const DocumentsContainer = styled(Paper)(({ theme }) => ({
  padding: theme.spacing(3),
  margin: theme.spacing(2),
  backgroundColor: theme.palette.background.paper,
  borderRadius: theme.spacing(1),
  height: 'calc(100vh - 140px)',
  overflow: 'auto',
}));

function Documents() {
  const [documents, setDocuments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [uploadFile, setUploadFile] = useState(null);
  const [uploading, setUploading] = useState(false);

  useEffect(() => {
    fetchDocuments();
  }, []);

  const fetchDocuments = async () => {
    setLoading(true);
    try {
      // Replace with your actual API endpoint
      const response = await fetch('http://localhost:5000/api/documents');
      const data = await response.json();
      
      if (data.success) {
        setDocuments(data.documents || []);
      } else {
        setError('Failed to load documents');
      }
    } catch (err) {
      console.error('Error fetching documents:', err);
      setError('Error connecting to server');
    } finally {
      setLoading(false);
    }
  };

  const handleFileChange = (event) => {
    setUploadFile(event.target.files[0]);
  };

  const handleUpload = async () => {
    if (!uploadFile) return;

    setUploading(true);
    const formData = new FormData();
    formData.append('file', uploadFile);

    try {
      // Replace with your actual upload endpoint
      const response = await fetch('http://localhost:5000/api/upload', {
        method: 'POST',
        body: formData,
      });

      const data = await response.json();

      if (data.success) {
        fetchDocuments(); // Refresh the document list
        setUploadFile(null);
      } else {
        setError('Upload failed: ' + (data.message || ''));
      }
    } catch (err) {
      console.error('Error uploading document:', err);
      setError('Error uploading document');
    } finally {
      setUploading(false);
    }
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleString();
  };

  return (
    <Box sx={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
      <Typography variant="h4" component="h1" gutterBottom sx={{ p: 2 }}>
        Team Documents
      </Typography>

      <DocumentsContainer elevation={3}>
        {error && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {error}
          </Alert>
        )}

        <Box sx={{ mb: 3, p: 2, border: '1px dashed grey', borderRadius: 1 }}>
          <Typography variant="h6" gutterBottom>
            Upload New Document
          </Typography>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
            <Button
              variant="contained"
              component="label"
              startIcon={<UploadFileIcon />}
            >
              Select File
              <input
                type="file"
                hidden
                onChange={handleFileChange}
              />
            </Button>
            {uploadFile && (
              <Typography variant="body2" sx={{ flex: 1 }}>
                {uploadFile.name}
              </Typography>
            )}
            <Button
              variant="contained"
              color="primary"
              onClick={handleUpload}
              disabled={!uploadFile || uploading}
            >
              {uploading ? <CircularProgress size={24} /> : 'Upload'}
            </Button>
          </Box>
        </Box>

        <Typography variant="h6" gutterBottom>
          Available Documents
        </Typography>

        {loading ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', mt: 3 }}>
            <CircularProgress />
          </Box>
        ) : documents.length === 0 ? (
          <Typography variant="body1" color="textSecondary">
            No documents available. Upload your first document above.
          </Typography>
        ) : (
          <List>
            {documents.map((doc, index) => (
              <React.Fragment key={doc.id || index}>
                <ListItem button>
                  <ListItemIcon>
                    <DescriptionIcon />
                  </ListItemIcon>
                  <ListItemText
                    primary={doc.filename || doc.name}
                    secondary={`Uploaded: ${formatDate(doc.uploaded_at || doc.created_at || new Date())}`}
                  />
                </ListItem>
                {index < documents.length - 1 && <Divider />}
              </React.Fragment>
            ))}
          </List>
        )}
      </DocumentsContainer>
    </Box>
  );
}

export default Documents;
